-- Remove the original demo tenant while preserving the bootstrap administrator.
-- The bootstrap administrator is intentionally retained so all other live
-- accounts and academic data can now be created through the Admin Portal.

delete from public.audit_logs
where actor_profile_id in (
  '20000000-0000-0000-0000-000000000102',
  '20000000-0000-0000-0000-000000000103',
  '20000000-0000-0000-0000-000000000104',
  '20000000-0000-0000-0000-000000000105',
  '20000000-0000-0000-0000-000000000201',
  '20000000-0000-0000-0000-000000000202',
  '20000000-0000-0000-0000-000000000203',
  '20000000-0000-0000-0000-000000000204',
  '20000000-0000-0000-0000-000000000205'
);

delete from public.announcements
where created_by in (
  '20000000-0000-0000-0000-000000000102',
  '20000000-0000-0000-0000-000000000103',
  '20000000-0000-0000-0000-000000000104',
  '20000000-0000-0000-0000-000000000105'
);

-- Offerings cascade to demo lecturer assignments, enrollments, assessments,
-- grade entries, and course results.
delete from public.course_offerings
where id in (
  '50000000-0000-0000-0000-000000001001',
  '50000000-0000-0000-0000-000000001002'
);

-- Removing the demo Auth users cascades to their profiles, roles, student and
-- staff records. The bootstrap administrator (...0101) is not removed.
delete from auth.users
where id in (
  '00000000-0000-0000-0000-000000000102',
  '00000000-0000-0000-0000-000000000103',
  '00000000-0000-0000-0000-000000000104',
  '00000000-0000-0000-0000-000000000105',
  '00000000-0000-0000-0000-000000000201',
  '00000000-0000-0000-0000-000000000202',
  '00000000-0000-0000-0000-000000000203',
  '00000000-0000-0000-0000-000000000204',
  '00000000-0000-0000-0000-000000000205'
);

delete from public.courses
where id in (
  '10000000-0000-0000-0000-000000001001',
  '10000000-0000-0000-0000-000000001002',
  '10000000-0000-0000-0000-000000001003',
  '10000000-0000-0000-0000-000000001004',
  '10000000-0000-0000-0000-000000001005'
);

delete from public.academic_periods
where id in (
  '10000000-0000-0000-0000-000000002001',
  '10000000-0000-0000-0000-000000002002'
);

delete from public.programmes
where id = '10000000-0000-0000-0000-000000000101';

delete from public.departments
where id = '10000000-0000-0000-0000-000000000001';
